INSERT INTO CLIENT_TEST (ID, NUMBER, SUMMARY, TYPE, CHECKER, ID_RELATED, CREATED_AT, UPDATED_AT)
VALUES (1, 100, 'Fixture summary', 0, 1, 1, '2025-01-01 00:01:00', '2025-01-01 00:01:00');

INSERT INTO CLIENT_TEST (ID, NUMBER, SUMMARY, TYPE, CHECKER, ID_RELATED, CREATED_AT, UPDATED_AT)
WITH RECURSIVE seq AS (
    SELECT 2 AS n
    UNION ALL
    SELECT n + 1 FROM seq WHERE n < 360
)
SELECT
    n AS ID,
    100 + (n % 40) AS NUMBER,
    CASE
        WHEN MOD(n, 15) = 0 THEN 'Critical path migration fixture'
        WHEN MOD(n, 11) = 0 THEN 'Performance smoke check'
        WHEN MOD(n, 7) = 0 THEN 'Fixture summary with searchable tokens'
        ELSE CONCAT('Summary item ', n)
    END AS SUMMARY,
    MOD(n, 5) AS TYPE,
    CASE WHEN MOD(n, 3) = 0 THEN 0 ELSE 1 END AS CHECKER,
    CASE WHEN MOD(n, 10) = 0 THEN NULL ELSE (MOD(n, 40) + 1) END AS ID_RELATED,
    TIMESTAMP('2025-01-01 00:00:00') + INTERVAL n MINUTE AS CREATED_AT,
    TIMESTAMP('2025-01-01 00:00:00') + INTERVAL n MINUTE AS UPDATED_AT
FROM seq;
